//高级查询
function queryList() {
    queryInfo.value.page = 1;
    queryInfo.value.pageSize = 15;
    initData();
}
//重置查询
function resetQuery() {
    queryInfo.value.page = 1;
    queryInfo.value.pageSize = 15;
    queryInfo.value.silo_name = '';
    queryInfo.value.symbol_name = '';
    queryInfo.value.rfa_path = '';
    queryInfo.value.create_account = '';
    queryInfo.value.update_account = '';
    initData();
}

//新任务
function newTask() {
    formState.value = 'add';
    dialogShow.value = true;
}

//编辑
function editRow(row) {
    formState.value = 'edit';
    GetOne(row.id, itemName).then((res) => {
        sheetData.value = res;
        dialogShow.value = true;
    });
}

//删除
function delRow(row) {
    Delete([row.id], itemName).then((res) => {
        executeRes(res);
    });
}

//提交
function btnSubmit() {
    formRef.value
        ?.validate((errors) => {
            if (!errors) {
                if (formState.value == 'add') {
                    Add(sheetData.value, itemName).then((res) => {
                        executeRes(res, translate, () => {
                            initData();
                            dialogShow.value = false;
                        });
                    });
                } else {
                    Update(sheetData.value, itemName).then((res) => {
                        executeRes(res, translate, () => {
                            initData();
                            dialogShow.value = false;
                        });
                    });
                }
            }
        })
        .catch((err) => {
            window.$message.warning(err[0][0].message);
        });
}

//取消
function btnCancel() {
    sheetData.value = {};
    dialogShow.value = false;
}

//翻页
function pageChange(page) {
    queryInfo.value.page = page;
    initData();
}
//改变页码
function pageSizeChange(pageSize) {
    queryInfo.value.page = 1;
    queryInfo.value.pageSize = pageSize;
    initData();
}

//选中行
